  ('judicial-57f41407-moex-00137', 'judicial-57f41407', 'judicial-57f41407-moex-114-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '檢察官所為發動偵查作為，下列敘述何者錯誤？', '["因被害人對甲提起告訴，檢察官得限期命司法警察調查之", "因路人告發乙犯竊盜罪，檢察官得限期命司法警察調查之", "因朋友私下告知丙涉嫌詐欺，檢察官不得限期命司法警察調查之", "因報紙報導知悉丁有犯罪嫌疑者，檢察官得限期命司法警察調查之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "941b955eb739", "answer_pdf_sha1": "cc7596b42a64", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00138', 'judicial-57f41407', 'judicial-57f41407-moex-114-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '下列何者不是限制辯護人與羈押中被告接見、互通書信的法定原因？', '["有事證足認其湮滅證據", "有事證足認其偽造證據", "有事證足認其勾串共犯或證人", "有事證足認被告逃亡"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "941b955eb739", "answer_pdf_sha1": "cc7596b42a64", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00139', 'judicial-57f41407', 'judicial-57f41407-moex-114-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於告訴乃論之罪，下列敘述何者正確？', '["告訴乃論之罪，對於共犯一人告訴，效力及於其他共犯", "告訴乃論之罪，對於共犯一人告發，效力及於其他共犯", "告訴乃論之罪，對於共犯一人自訴，效力及於其他共犯", "告訴乃論之罪，對於共犯一人提起公訴，效力及於其他共犯"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "941b955eb739", "answer_pdf_sha1": "cc7596b42a64", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00140', 'judicial-57f41407', 'judicial-57f41407-moex-114-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於緩起訴處分之敘述，下列何者錯誤？', '["撤銷緩起訴處分，被告可以聲請再議", "期滿未經撤銷，如不具備刑事訴訟法第260條第1項所定之要件，不得再行起訴", "於緩起訴前，因過失犯罪，而在緩起訴期間內受有期徒刑以上刑之宣告者，檢察官得依職權或依告 訴人之聲請，撤銷緩起訴處分", "於緩起訴期間，違背緩起訴處分應遵守或履行事項者，檢察官得依職權或依告訴人之聲請，撤銷緩 起訴處分"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:36+00:00", "source_pdf_sha1": "941b955eb739", "answer_pdf_sha1": "cc7596b42a64", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
